{"content":"let products = [
  { id: 1, sku: 'LTP-1000', name: 'Laptop', price: 999, inventory: 12, available: true },
  { id: 2, sku: 'PHN-2000', name: 'Phone', price: 699, inventory: 0, available: false },
  { id: 3, sku: 'TBL-3000', name: 'Tablet', price: 499, inventory: 24, available: true },
  { id: 4, sku: 'HDP-4000', name: 'Headphones', price: 199, inventory: 42, available: true },
  { id: 5, sku: 'WTC-5000', name: 'Watch', price: 299, inventory: 8, available: true }
];

function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function getAllProducts() {
  await delay(100);

  return products.map((product) => ({ ...product }));
}

export async function syncProductsFromUpstream() {
  await delay(2000);

  products = products.map((product, index) => {
    const inventory = Math.max(0, product.inventory + (index % 2 === 0 ? 5 : -3));
    const priceDelta = index % 2 === 0 ? 25 : -15;

    return {
      ...product,
      price: Math.max(99, product.price + priceDelta),
      inventory,
      available: inventory > 0
    };
  });

  return products;
}
